export const firstCandleCrossBothSide = (candles) => {
    let lowHit = false;
    let highHit = false;
    let highCandle;
    let lowCandle;
    let direction;
    let engulfeUp = false;
    let engulfeDown = false;
    let hit = false;
    let buyOrSellPrice;
    let stopLoss = 0;
    let inProgress = false;
    let stoplossPriceDown = 0;
    let stoplossPriceUp = 0;
    candles.forEach((val, index) => {
        if (candles[0].high < val.high) {
            highHit = true;
            if (lowHit && !direction) {
                direction = 'up';
                highCandle = { high: val.high, low: val.low };
            }
        }
        if (candles[0].low > val.low) {
            lowHit = true;
            if (highHit && !direction) {
                direction = 'down';
                lowCandle = { high: val.high, low: val.low };
            }
        }
        if (direction && !hit) {
            if (direction === 'up' && val.high > highCandle.high && !engulfeUp) {
                highCandle = { high: val.high, low: val.low };
            }
            if (direction === 'down' && val.low < lowCandle.low && !engulfeDown) {
                lowCandle = { high: val.high, low: val.low };
            }

            if (direction === 'up' && highCandle.low > val.low && !hit) {
                engulfeUp = true;
                inProgress = true;
                stoplossPriceUp = val.low;
            }
            if (direction === 'down' && lowCandle.high < val.high && !hit) {
                engulfeDown = true;
                inProgress = true;
                stoplossPriceDown = val.high;
            }

            if (engulfeUp && highCandle.high < val.high && index < 21) {
                hit = true;
                buyOrSellPrice = highCandle.high;
            }
            if (engulfeDown && lowCandle.low > val.low && index < 21) {
                hit = true;
                buyOrSellPrice = lowCandle.low;
            }
        }
        if(hit) {
            if (direction === 'up' && val.low < stoplossPriceUp) {
                stopLoss = stoplossPriceUp;
            } else if (direction === 'down' && val.high > stoplossPriceDown) {
                stopLoss = stoplossPriceDown;
            }
        }
    });
    const target = direction === 'up' ? stopLoss || candles[candles.length - 1].high : stopLoss || candles[candles.length - 1]?.low;
    return {
        buyOrSellPrice: buyOrSellPrice,
        target: target,
        inProgress: inProgress,
        profitOrLoss: direction === 'up' ? Math.floor(target - buyOrSellPrice) : Math.floor(buyOrSellPrice - target),
        direction: direction,
        // match: match,
        time: candles[0].date,
        hit: hit,
    };
}

export const engulfe = (candles) => {

    let hit = false;
    let buyOrSellPrice;
    let stopLoss = 0;
    let direction;
    let inProgress = false;
    let isSucess = false;

    for (let i = 2; i < candles.length; i++) {

        // 🔒 Safety check (avoid undefined access)
        if (!candles[i + 4]) break;

        let baseIndex = i;
        let upPhase1 = false;
        let downPhase1 = false;

        // =========================
        // 🔁 DYNAMIC PHASE-1 (SHIFT)
        // =========================
        for (let shift = 0; shift <= 2; shift++) {

            if (!candles[i + shift] || !candles[i - 2 + shift]) continue;

            let c0 = candles[i - 2 + shift];
            let c1 = candles[i - 1 + shift];
            let c2 = candles[i + shift];

            // 🔼 Uptrend phase-1
            if (
                c1.close > c0.high &&
                c1.low > c0.low &&
                c2.close > c1.high &&
                c2.low > c1.low
            ) {
                baseIndex = i + shift;
                upPhase1 = true;
            }

            // 🔽 Downtrend phase-1
            if (
                c1.close < c0.low &&
                c1.high < c0.high &&
                c2.close < c1.low &&
                c2.high < c1.high
            ) {
                baseIndex = i + shift;
                downPhase1 = true;
            }
        }

        // =========================
        // 🔼 UPTREND FLOW
        // =========================
        if (upPhase1 && !hit) {

            let pullbackStart = baseIndex + 1;
            let pullbackEnd = baseIndex + 3;

            if (!candles[pullbackEnd]) continue;

            let validPullback = true;
            let pullbackLow = candles[pullbackStart].low;

            // ❌ Strict pullback validation
            for (let k = pullbackStart; k <= pullbackEnd; k++) {

                if (!candles[k]) {
                    validPullback = false;
                    break;
                }

                if (
                    candles[k].low < candles[baseIndex].low ||
                    candles[k].low <= candles[baseIndex - 1].low
                ) {
                    validPullback = false;
                }

                pullbackLow = Math.min(pullbackLow, candles[k].low);
            }

            if (validPullback) {

                let prevHigh = candles[pullbackStart].high;
                let breakoutCount = 0;

                for (
                    let j = pullbackEnd + 1;
                    j < Math.min(pullbackEnd + 5, candles.length);
                    j++
                ) {

                    if (!candles[j]) break;

                    if (candles[j].high > prevHigh) {
                        breakoutCount++;
                        prevHigh = candles[j].high;

                        if (breakoutCount === 2) {
                            inProgress = true;
                            direction = 'up';
                            buyOrSellPrice = prevHigh;
                        }

                        if (breakoutCount === 4) {
                            hit = true;
                            isSucess = true;
                            stopLoss = pullbackLow;
                            break;
                        }

                    } else {
                        break;
                    }
                }
            }
        }

        // =========================
        // 🔽 DOWNTREND FLOW
        // =========================
        if (downPhase1 && !hit) {

            let pullbackStart = baseIndex + 1;
            let pullbackEnd = baseIndex + 3;

            if (!candles[pullbackEnd]) continue;

            let validPullback = true;
            let pullbackHigh = candles[pullbackStart].high;

            for (let k = pullbackStart; k <= pullbackEnd; k++) {

                if (!candles[k]) {
                    validPullback = false;
                    break;
                }

                if (
                    candles[k].high > candles[baseIndex].high ||
                    candles[k].high >= candles[baseIndex - 1].high
                ) {
                    validPullback = false;
                }

                pullbackHigh = Math.max(pullbackHigh, candles[k].high);
            }

            if (validPullback) {

                let prevLow = candles[pullbackStart].low;
                let breakdownCount = 0;

                for (
                    let j = pullbackEnd + 1;
                    j < Math.min(pullbackEnd + 5, candles.length);
                    j++
                ) {

                    if (!candles[j]) break;

                    if (candles[j].low < prevLow) {
                        breakdownCount++;
                        prevLow = candles[j].low;

                        if (breakdownCount === 2) {
                            inProgress = true;
                            direction = 'down';
                            buyOrSellPrice = prevLow;
                        }

                        if (breakdownCount === 4) {
                            hit = true;
                            isSucess = true;
                            stopLoss = pullbackHigh;
                            break;
                        }

                    } else {
                        break;
                    }
                }
            }
        }

        if (hit) break;
    }

    const lastCandle = candles[candles.length - 1];

    const target =
        direction === 'up'
            ? lastCandle?.high
            : lastCandle?.low;

    return {
        buyOrSellPrice,
        target,
        profitOrLoss:
            direction === 'up'
                ? Math.floor((target || 0) - (buyOrSellPrice || 0))
                : Math.floor((buyOrSellPrice || 0) - (target || 0)),
        direction,
        time: candles[0]?.date,
        hit,
        inProgress,
        isSucess,
    };
};

export const fourInsideOne = (candles, previousDayCandles) => {
    let lastFiveCandle = previousDayCandles?.slice(19, 24);
    const { lastDayHigh, lastDayLow } = getHighAndLow(lastFiveCandle);
    let match = [];
    let direction;
    let hit = false;
    let buyOrSellPrice = 0;
    let stopLoss = 0;
    let inProgress = false;
    let isSucess = true;
    candles.forEach((val, index) => {
        if (match.length === 0) {
            match.push(val);
        } else if(isSucess) {
            if (match[0].high > val.high && match[0].low < val.low && isSucess) {
                if (match.length !== 5) {
                    match.push(val);
                }
            } else {
                if (match.length !== 5 && isSucess) {
                    match = [];
                    isSucess = false;
                }
            }
        }
        if (match.length === 5 && index < 20) {
            inProgress = true;
            if (match[0].high < val.high && !hit) {
                if(((match[0]?.high - lastDayLow)/match[0]?.high)*100 > 1.75) {
                    isSucess = false;
                } else {
                    direction = 'up';
                    hit = true;
                    buyOrSellPrice = match[0].high;
                }
            } else if (match[0].low > val.low && !hit) {
                if(((lastDayHigh - match[0]?.low)/match[0]?.low)*100 > 1.75) {
                    isSucess = false;
                } else {
                    direction = 'low';
                    hit = true;
                    buyOrSellPrice = match[0].low;
                }
            }
        }
        if (hit) {
            if (direction === 'up' && match[0].low > val.low) {
                stopLoss = match[0].low;
            } else if (direction === 'low' && match[0].high < val.high) {
                stopLoss = match[0].high;
            }
        }
    });

    const target = direction === 'up' ? (stopLoss || candles[candles.length - 1].high) : (stopLoss || candles[candles.length - 1]?.low);
    return {
        buyOrSellPrice: buyOrSellPrice,
        target: target,
        profitOrLoss: direction === 'up' ? Math.floor(target - buyOrSellPrice) : Math.floor(buyOrSellPrice - target),
        direction: direction,
        // match: match,
        time: match[0]?.date,
        hit: hit,
        inProgress: inProgress,
        isSucess: isSucess,
    };
}

